import React, { useState, useContext } from 'react';
import { AuthContext } from '../contexts/AuthContext';
import { useNavigate, Link } from 'react-router-dom';

const API_URL = 'http://localhost:3001/api';

export default function AuthForm({ mode = 'login' }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login, signup } = useContext(AuthContext);
  const navigate = useNavigate();

  const submit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      if (mode === 'login') {
        await login(username, password);
      } else {
        await signup(username, password);
      }
      navigate('/');
    } catch (err) {
      setError(err.message || 'Authentication failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center px-4 py-12 bg-hero">
      {/* Background decorations */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-gold-500/5 rounded-full blur-3xl" />
        <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-purple-500/5 rounded-full blur-3xl" />
      </div>

      <div className="w-full max-w-md relative z-10 animate-fade-in">
        {/* Logo */}
        <div className="mb-8 text-center">
          <div className="w-16 h-16 mx-auto rounded-2xl bg-gradient-to-br from-gold-400 to-gold-600 flex items-center justify-center shadow-xl shadow-gold-500/20 mb-4">
            <span className="text-navy-900 text-3xl font-black">♔</span>
          </div>
          <h1 className="text-3xl font-extrabold tracking-tight text-white">
            Chess<span className="text-gradient-gold">Arena</span>
          </h1>
          <p className="mt-2 text-slate-400 text-sm">
            {mode === 'login'
              ? 'Sign in to compete in real-time tournaments'
              : 'Create an account and start winning'}
          </p>
        </div>

        {/* Form Card */}
        <div className="card-glass p-7">
          <h2 className="text-xl font-bold mb-6 text-white">
            {mode === 'login' ? 'Welcome back' : 'Create account'}
          </h2>

          <form onSubmit={submit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-300 mb-2">Username</label>
              <input
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                placeholder="Enter username"
                className="input-field"
                required
                autoComplete="username"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-300 mb-2">Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Enter password"
                className="input-field"
                required
                autoComplete={mode === 'login' ? 'current-password' : 'new-password'}
                minLength={4}
              />
            </div>

            {error && (
              <div className="p-3 rounded-xl bg-red-500/10 border border-red-500/20">
                <p className="error">{error}</p>
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="btn-primary w-full btn-lg"
            >
              {loading ? (
                <span className="flex items-center justify-center gap-2">
                  <svg className="animate-spin w-5 h-5" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
                  </svg>
                  Processing...
                </span>
              ) : mode === 'login' ? (
                'Sign In'
              ) : (
                'Create Account'
              )}
            </button>
          </form>

          <div className="mt-6 text-sm text-center text-slate-400">
            {mode === 'login' ? (
              <>
                New to Chess Arena?{' '}
                <Link to="/signup" className="text-gold-400 font-semibold hover:text-gold-300 transition-colors">
                  Create account
                </Link>
              </>
            ) : (
              <>
                Already have an account?{' '}
                <Link to="/login" className="text-gold-400 font-semibold hover:text-gold-300 transition-colors">
                  Sign in
                </Link>
              </>
            )}
          </div>
        </div>

        {/* Signup bonus notice */}
        {mode === 'signup' && (
          <div className="mt-4 p-3 rounded-xl bg-emerald-500/5 border border-emerald-500/10 text-center animate-slide-up">
            <p className="text-emerald-400 text-sm font-medium">🎁 Get ₹1,000 bonus on signup!</p>
          </div>
        )}
      </div>
    </div>
  );
}
